// src/core/report.ts
function nestReportUnderParent(report) {
  const lines = report.split("\n");
  let h1Stripped = false;
  const out = [];
  for (const line of lines) {
    const m = /^(#+)\s/.exec(line);
    if (m) {
      if (!h1Stripped && m[1].length === 1) {
        h1Stripped = true;
        continue;
      }
      out.push("#" + line);
      h1Stripped = true;
      continue;
    }
    out.push(line);
  }
  return out.join("\n");
}

